                        equals(body('Filter_textblocks')[0]?['hso_positionelementtype'],100000004),
                            body('Filter_textblocks')[0]?['AProjecthourTextblock.hso_name'],
                            if(
                            equals(body('Filter_textblocks')[0]?['hso_positionelementtype'],100000003),
                                body('Filter_textblocks')[0]?['AProductionhourTextblock.hso_name'],
                                if(
                                equals(body('Filter_textblocks')[0]?['hso_positionelementtype'],100000007),
